#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/wait.h>
static unsigned char buf[8], obuf[64], want[64];
int main(int argc,char**argv){
 if(argc<3){ fprintf(stderr,"usage: %s maxlen byte [byte...]\n",argv[0]); return 1; }
 int maxlen=atoi(argv[1]);
 int wlen=argc-2;
 for(int i=0;i<wlen;i++) want[i]=(unsigned char)strtol(argv[2+i],0,16);
 for(int len=1;len<=maxlen;len++){
  long total=1; for(int i=0;i<len;i++) total*=256;
  for(long v=0;v<total;v++){
   long x=v; for(int i=0;i<len;i++){buf[i]=x&0xff;x>>=8;}
   FILE *f=fopen("/tmp/find.in","wb"); if(!f) continue; fwrite(buf,1,len,f); fclose(f);
   int pid=fork();
   if(pid==0){
    freopen("/tmp/find.in","rb",stdin);
    freopen("/tmp/find.out","wb",stdout);
    freopen("/dev/null","w",stderr);
    execl("/app/decomp","/app/decomp",(char*)0);
    _exit(127);
   }
   int status=0; while(waitpid(pid,&status,0)<0 && pid>0);
   FILE *o=fopen("/tmp/find.out","rb"); if(!o) continue;
   int got=0,ch; while((ch=fgetc(o))!=EOF && got<64) obuf[got++]=ch; fclose(o);
   if(got==wlen && memcmp(obuf,want,wlen)==0){
    printf("FOUND len=%d bytes",len);
    for(int i=0;i<len;i++) printf(" %02x",buf[i]);
    printf(" ->"); for(int b=0;b<wlen;b++) printf(" %02x",want[b]);
    printf("\n"); fflush(stdout);
   }
  }
 }
 return 0;
}
